  ('elementary-f29af906-moex-00728', 'elementary-f29af906', 'elementary-f29af906-moex-111-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '經依公司法認許之陸資公司得申請取得、設定或移轉已登記之不動產物權係指下列那一項？', '["業務人員居住之住宅", "營業處所、辦公場所、商店及工廠", "外僑子弟學校", "醫院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "208367d378a7", "answer_pdf_sha1": "3d44171b3f1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
