  ('elementary-f29af906-moex-00733', 'elementary-f29af906', 'elementary-f29af906-moex-111-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依中央行政機關組織基準法第6條規定，中央行政機關之名稱定名，下列何者錯誤？', '["一級機關用院", "二級機關用部", "二級機關或獨立機關用委員會", "四級機關用署或局"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:55+00:00", "source_pdf_sha1": "3dc4d7df7965", "answer_pdf_sha1": "f263afdcf172", "source_family": "moex-gov-tw", "moex": {"exam_code": "111010", "c": "513", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "111", "exam_name": "111年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
